args.sparql:
SELECT ?player ?playerLabel ?goals
WHERE {
  wd:Q4591311 p:P4006 ?participation.
  ?participation ps:P4006 ?player.
  ?participation pq:P1532 ?goals.
  SERVICE <https://qlever.cs.uni-freiburg.de/api/wikidata> {
    ?player rdfs:label ?playerLabel FILTER (LANG(?playerLabel) = "en").
  }
}
ORDER BY DESC(xsd:integer(?goals))
LIMIT 1
